<?php
namespace Database\Seeders;use App\Domain\GameHome\GameHomeCardDestinationType;use App\Models\GameHomeCard;use Illuminate\Database\Seeder;
class GameHomeCardSeeder extends Seeder{public function run(){foreach([['change-character','Cambiar de PJ',GameHomeCardDestinationType::CHARACTER_SELECTOR,null,10],['my-character','Mi PJ',GameHomeCardDestinationType::ACTIVE_CHARACTER_OVERVIEW,null,20],['world','Mundo',GameHomeCardDestinationType::ROUTE,'worlds.index',30]]as$row){$card=GameHomeCard::where('code',$row[0])->first();if(!$card){GameHomeCard::create(['code'=>$row[0],'name'=>$row[1],'destination_type'=>$row[2],'destination_value'=>$row[3],'sort_order'=>$row[4],'is_active'=>true,'opens_new_tab'=>false]);continue;}if($row[0]==='world'&&!($card->destination_type===GameHomeCardDestinationType::ROUTE&&in_array($card->destination_value,['world-maps.index','worlds.index'],true)))continue;$card->destination_type=$row[2];$card->destination_value=$row[3];$card->save();}}}
